def get_insider_activity(symbol: str) -> pd.DataFrame:
    """Get insider activity. [Source: Business Insider]

    Parameters
    ----------
    symbol : str
        Ticker symbol to get insider activity data from

    Returns
    -------
    df_insider : pd.DataFrame
        Insider activity data
    """
    url_market_business_insider = (
        f"https://markets.businessinsider.com/stocks/{symbol.lower()}-stock"
    )
    text_soup_market_business_insider = BeautifulSoup(
        request(
            url_market_business_insider, headers={"User-Agent": get_user_agent()}
        ).text,
        "lxml",
    )

    d_insider = dict()
    l_insider_vals = list()
    for idx, insider_val in enumerate(
        text_soup_market_business_insider.findAll(
            "td", {"class": "table__td text-center"}
        )
    ):
        l_insider_vals.append(insider_val.text.strip())

        # Add value to dictionary
        if (idx + 1) % 6 == 0:
            # Check if we are still parsing insider trading activity
            if "/" not in l_insider_vals[0]:
                break
            d_insider[(idx + 1) // 6] = l_insider_vals
            l_insider_vals = list()

    df_insider = pd.DataFrame.from_dict(
        d_insider,
        orient="index",
        columns=["Date", "Shares Traded", "Shares Held", "Price", "Type", "Option"],
    )

    df_insider["Date"] = pd.to_datetime(df_insider["Date"])

    l_names = list()
    for s_name in text_soup_market_business_insider.findAll(
        "a", {"onclick": "silentTrackPI()"}
    ):
        l_names.append(s_name.text.strip())
    df_insider["Insider"] = l_names
    df_insider = df_insider.set_index("Date")
    df_insider = df_insider.sort_index(ascending=True)
    return df_insider

def test_closure_nondiff(self):
    # https://github.com/google/jax/issues/3584

    def dz_dt(z, t):
      return jnp.stack([z[0], z[1]])

    def f(z):
      y = odeint(dz_dt, z, jnp.arange(10.))
      return jnp.sum(y)

    jax.grad(f)(jnp.ones(2))

def test_transaction_clusterer_bumps_rules(_, default_organization):
    tmp_redis_storage = {}

    class MockRedisRuleStore:
        def read(self, project: Project) -> RuleSet:
            return tmp_redis_storage.get(project, {})

        def write(self, project: Project, rules) -> None:
            tmp_redis_storage[project] = rules

    with mock.patch(
        "sentry.ingest.transaction_clusterer.rules.RedisRuleStore", MockRedisRuleStore
    ), Feature({"organizations:transaction-name-clusterer": True}):
        project1 = Project(id=123, name="project1", organization_id=default_organization.id)
        project1.save()
        for i in range(10):
            _store_transaction_name(project1, f"/user/tx-{project1.name}-{i}/settings")

        with mock.patch("sentry.ingest.transaction_clusterer.rules._now", lambda: 1):
            spawn_clusterers()

        assert _get_rules(project1) == {"/user/*/**": 1}

        with mock.patch("sentry.ingest.transaction_clusterer.rules._now", lambda: 2):
            record_transaction_name(
                project1,
                {
                    "transaction": "/user/*/settings",
                    "transaction_info": {"source": "sanitized"},
                    "_meta": {
                        "transaction": {
                            "": {
                                "rem": [["int", "s", 0, 0], ["/user/*/**", "s"]],
                                "val": "/user/tx-project1-pi/settings",
                            }
                        }
                    },
                },
            )

        # _get_rules fetches from project options, which arent updated yet.
        assert _get_rules(project1) == {"/user/*/**": 1}
        # Update rules to update the project option storage.
        with mock.patch("sentry.ingest.transaction_clusterer.rules._now", lambda: 3):
            update_rules(project1, [])
        # After project options are updated, the last_seen should also be updated.
        assert _get_rules(project1) == {"/user/*/**": 2}

